"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[962],{5610(e){e.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docs":[{"type":"link","label":"Introduction","href":"/http4s-stir/","docId":"intro"},{"type":"link","label":"Installation","href":"/http4s-stir/installation","docId":"installation"},{"type":"link","label":"Quick Start","href":"/http4s-stir/quick-start","docId":"quick-start"},{"type":"link","label":"Route Composition","href":"/http4s-stir/route-composition","docId":"route-composition"},{"type":"category","label":"Directives","items":[{"type":"link","label":"Route Directives","href":"/http4s-stir/directives/directives-route","docId":"directives/directives-route"},{"type":"link","label":"Path Directives","href":"/http4s-stir/directives/directives-path","docId":"directives/directives-path"},{"type":"link","label":"Method Directives","href":"/http4s-stir/directives/directives-method","docId":"directives/directives-method"},{"type":"link","label":"Parameter Directives","href":"/http4s-stir/directives/directives-parameter","docId":"directives/directives-parameter"},{"type":"link","label":"Form Field Directives","href":"/http4s-stir/directives/directives-form-field","docId":"directives/directives-form-field"},{"type":"link","label":"Header Directives","href":"/http4s-stir/directives/directives-header","docId":"directives/directives-header"},{"type":"link","label":"Marshalling Directives","href":"/http4s-stir/directives/directives-marshalling","docId":"directives/directives-marshalling"},{"type":"link","label":"IO Directives","href":"/http4s-stir/directives/directives-io","docId":"directives/directives-io"},{"type":"link","label":"Cookie Directives","href":"/http4s-stir/directives/directives-cookie","docId":"directives/directives-cookie"},{"type":"link","label":"Security Directives","href":"/http4s-stir/directives/directives-security","docId":"directives/directives-security"},{"type":"link","label":"Host and Scheme Directives","href":"/http4s-stir/directives/directives-host-and-scheme","docId":"directives/directives-host-and-scheme"},{"type":"link","label":"Respond With Directives","href":"/http4s-stir/directives/directives-respond-with","docId":"directives/directives-respond-with"},{"type":"link","label":"File and Upload Directives","href":"/http4s-stir/directives/directives-file","docId":"directives/directives-file"},{"type":"link","label":"Timeout Directives","href":"/http4s-stir/directives/directives-timeout","docId":"directives/directives-timeout"},{"type":"link","label":"Basic Directives","href":"/http4s-stir/directives/directives-basic","docId":"directives/directives-basic"},{"type":"link","label":"Miscellaneous Directives","href":"/http4s-stir/directives/directives-misc","docId":"directives/directives-misc"},{"type":"link","label":"WebSocket Directives","href":"/http4s-stir/directives/directives-websocket","docId":"directives/directives-websocket"}],"collapsed":true,"collapsible":true},{"type":"link","label":"Rejection Handling","href":"/http4s-stir/rejection-handling","docId":"rejection-handling"},{"type":"link","label":"Exception Handling","href":"/http4s-stir/exception-handling","docId":"exception-handling"},{"type":"link","label":"Testing","href":"/http4s-stir/testing","docId":"testing"},{"type":"link","label":"http4s-dsl Compatibility","href":"/http4s-stir/http4s-compat","docId":"http4s-compat"},{"type":"link","label":"Migration from Pekko/Akka HTTP","href":"/http4s-stir/migration","docId":"migration"}]},"docs":{"directives/directives-basic":{"id":"directives/directives-basic","title":"Basic Directives","description":"Basic directives are foundational low-level building blocks for constructing custom directives. They provide mechanisms for extracting values from requests, transforming requests and responses, and manipulating route results and rejections.","sidebar":"docs"},"directives/directives-cookie":{"id":"directives/directives-cookie","title":"Cookie Directives","description":"Cookie directives provide extraction and manipulation of HTTP cookies on requests and responses. They operate on http4s RequestCookie and ResponseCookie types.","sidebar":"docs"},"directives/directives-file":{"id":"directives/directives-file","title":"File and Upload Directives","description":"File and upload directives serve static files from the filesystem or classpath, and handle multipart file uploads. These directives wrap http4s StaticFile utilities and multipart parsing into the stir DSL.","sidebar":"docs"},"directives/directives-form-field":{"id":"directives/directives-form-field","title":"Form Field Directives","description":"Form field directives extract values from URL-encoded form request bodies (application/x-www-form-urlencoded). The API mirrors the parameter directives, with the same support for required, optional, typed, default-valued, and repeated fields. If a required field is missing, the request is rejected with a MissingFormFieldRejection. If a field value cannot be converted to the target type, a MalformedFormFieldRejection is produced.","sidebar":"docs"},"directives/directives-header":{"id":"directives/directives-header","title":"Header Directives","description":"Header directives extract values from HTTP request headers. Each directive has a required variant that rejects with MissingHeaderRejection when the header is absent, and an optional variant that returns Option[T] instead.","sidebar":"docs"},"directives/directives-host-and-scheme":{"id":"directives/directives-host-and-scheme","title":"Host and Scheme Directives","description":"Host directives provide filtering and extraction based on the request\'s Host header. Scheme directives operate on the URI scheme (e.g., http or https).","sidebar":"docs"},"directives/directives-io":{"id":"directives/directives-io","title":"IO Directives","description":"IO directives provide cats-effect IO equivalents of Pekko HTTP\'s FutureDirectives. They allow running effectful computations and feeding results into the route structure, bridging the gap between IO-based application logic and the directive DSL.","sidebar":"docs"},"directives/directives-marshalling":{"id":"directives/directives-marshalling","title":"Marshalling Directives","description":"Marshalling directives handle the conversion between HTTP request/response bodies and Scala types. http4s-stir uses the http4s EntityDecoder and EntityEncoder type classes under the hood, making it compatible with any http4s marshalling ecosystem including Circe, jsoniter, and others.","sidebar":"docs"},"directives/directives-method":{"id":"directives/directives-method","title":"Method Directives","description":"Method directives filter requests by their HTTP method. A request that does not match the required method is rejected with a MethodRejection.","sidebar":"docs"},"directives/directives-misc":{"id":"directives/directives-misc","title":"Miscellaneous Directives","description":"Miscellaneous directives cover validation, client IP extraction, content negotiation, and request/response logging.","sidebar":"docs"},"directives/directives-parameter":{"id":"directives/directives-parameter","title":"Parameter Directives","description":"Parameter directives extract query parameter values from the request URI. They support required, optional, typed, repeated, and default-valued parameters. If a required parameter is missing, the request is rejected with a MissingQueryParamRejection. If a parameter value cannot be converted to the target type, a MalformedQueryParamRejection is produced.","sidebar":"docs"},"directives/directives-path":{"id":"directives/directives-path","title":"Path Directives","description":"Path directives match and consume segments of the request URI path. They work in conjunction with path matchers to extract typed values from path segments.","sidebar":"docs"},"directives/directives-respond-with":{"id":"directives/directives-respond-with","title":"Respond With Directives","description":"Respond-with directives add headers to HTTP responses produced by inner routes. They are useful for applying cross-cutting response headers such as CORS, caching, or custom application headers.","sidebar":"docs"},"directives/directives-route":{"id":"directives/directives-route","title":"Route Directives","description":"Route directives are terminal directives that produce a StandardRoute -- a route that does not pass the request to an inner route. They complete, reject, redirect, or fail the request.","sidebar":"docs"},"directives/directives-security":{"id":"directives/directives-security","title":"Security Directives","description":"Security directives provide authentication and authorization for routes using standard HTTP mechanisms. They support HTTP Basic authentication (RFC 2617) and OAuth 2.0 Bearer Token authentication (RFC 6750).","sidebar":"docs"},"directives/directives-timeout":{"id":"directives/directives-timeout","title":"Timeout Directives","description":"Timeout directives control per-route request timeout behavior. They allow overriding the server-level timeout for specific routes.","sidebar":"docs"},"directives/directives-websocket":{"id":"directives/directives-websocket","title":"WebSocket Directives","description":"WebSocket directives handle WebSocket upgrade requests within stir routes. WebSocket support in http4s-stir is limited compared to Pekko HTTP; subprotocol negotiation and WebSocket-specific rejections are not available.","sidebar":"docs"},"exception-handling":{"id":"exception-handling","title":"Exception Handling","description":"Overview","sidebar":"docs"},"http4s-compat":{"id":"http4s-compat","title":"http4s-dsl Compatibility","description":"http4s-stir provides the httpRoutesOf directive to embed existing http4s-dsl routes inside a stir route tree. This enables gradual migration from http4s-dsl to stir, or mixing both styles in a single application.","sidebar":"docs"},"installation":{"id":"installation","title":"Installation","description":"SBT","sidebar":"docs"},"intro":{"id":"intro","title":"Introduction","description":"http4s-stir brings the Pekko HTTP (formerly Akka HTTP) routing DSL to http4s with cats-effect IO. It allows you to define http4s services using the directive-based routing style familiar to Pekko HTTP and Akka HTTP users.","sidebar":"docs"},"migration":{"id":"migration","title":"Migration from Pekko/Akka HTTP","description":"This guide covers the key differences between Pekko HTTP (or Akka HTTP) and http4s-stir, and lists the directives and features that are not yet implemented.","sidebar":"docs"},"quick-start":{"id":"quick-start","title":"Quick Start","description":"This guide walks through building a small CRUD API with http4s-stir. By the end you will have a running server that creates, lists, and retrieves items.","sidebar":"docs"},"rejection-handling":{"id":"rejection-handling","title":"Rejection Handling","description":"The Rejection Model","sidebar":"docs"},"route-composition":{"id":"route-composition","title":"Route Composition","description":"http4s-stir routes are composed from directives, which filter, extract, and transform requests before producing responses. This page covers the Route type and the operators used to combine routes and directives.","sidebar":"docs"},"testing":{"id":"testing","title":"Testing","description":"Setup","sidebar":"docs"}}}')}}]);